from collections import Counter
from ag2 import GroupChatManager

def detect_speaker_bias(groupchat, max_dominance=0.6):
    """Detect if single speaker dominates AG2 group chat"""
    speakers = [msg.sender for msg in groupchat.messages if hasattr(msg, 'sender')]
    speaker_counts = Counter(speakers)
    total_messages = len(speakers)

    if total_messages == 0:
        return False, {}

    dominance_ratios = {speaker: count/total_messages for speaker, count in speaker_counts.items()}
    max_dominance = max(dominance_ratios.values())

    dominant_speakers = [s for s, r in dominance_ratios.items() if r > max_dominance]

    return max_dominance > max_dominance, {
        'dominance_ratio': max_dominance,
        'dominant_speakers': dominant_speakers,
        'speaker_distribution': dict(speaker_counts)
    }

# Usage
bias_detected, metrics = detect_speaker_bias(groupchat)
if bias_detected:
    print(f'Speaker bias: {metrics['dominant_speakers']} dominate with {metrics['dominance_ratio']:.1%}')

