import ast
import re
from ag2 import CodeAgent

class SafeCodeValidator:
    DANGEROUS_PATTERNS = [
        r'open\(\s*["\'](/|\\)',  # Root file access
        r'os\.(remove|rmdir|unlink|system|pop\d*)\s*\(\s*["\'][^,]',
        r'subprocess\.(run|call|check_call|check_output)',
        r'exec\(|eval\(',
        r'__import__\s*\(\s*["\'](?:os|subprocess|sys)',
    ]

    @staticmethod
    def is_safe(code):
        # Parse AST for dangerous constructs
        try:
            tree = ast.parse(code)
            for node in ast.walk(tree):
                if isinstance(node, ast.Call):
                    func_name = ast.unparse(node.func)
                    for pattern in SafeCodeValidator.DANGEROUS_PATTERNS:
                        if re.search(pattern, func_name, re.IGNORECASE):
                            return False
        except:
            pass

        # Regex check for dangerous strings
        for pattern in SafeCodeValidator.DANGEROUS_PATTERNS:
            if re.search(pattern, code, re.IGNORECASE):
                return False

        return True

# Wrap AG2 CodeAgent
class SafeCodeAgent(CodeAgent):
    def generate_code(self, task):
        code = super().generate_code(task)
        if not SafeCodeValidator.is_safe(code):
            return "# CODE REJECTED: Contains unsafe operations"
        return code
